import { isArray } from "../../utils/zcutils";

/*
 * _d - data
 * _dA - dataAccessor
 * selection.data - changes data in the given selection
 */
export function data(_d, _dA) {
    var s = this.selection;

    var _s = isArray(s) ? s : [s];
    for (var i = 0; i < _s.length; i++) {
        _s[i].data = _d;
        _s[i].dataAccessor = _dA;
    }
    return this;
}
